import{_ as a,o as t,c as i,a2 as o}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"ADR-035 — Diagram authoring pipeline: hand-drawn SVG, sources committed","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-035.md","filePath":"adr/ADR-035.md"}'),s={name:"adr/ADR-035.md"};function r(n,e,c,d,l,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-035-—-diagram-authoring-pipeline-hand-drawn-svg-sources-committed" tabindex="-1">ADR-035 — Diagram authoring pipeline: hand-drawn SVG, sources committed <a class="header-anchor" href="#adr-035-—-diagram-authoring-pipeline-hand-drawn-svg-sources-committed" aria-label="Permalink to &quot;ADR-035 — Diagram authoring pipeline: hand-drawn SVG, sources committed&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-011 (with ADR-034, ADR-036) TA anchor · §components / primary-route-pages Related · PRD-008, ADR-016 (build-time assets), ADR-019 (ajv schema validation)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-008 §design hints calls for ~30 SVG diagrams in <code>/science</code> — one per geometric concept (orbits, conic sections, transfer ellipses, porkchop axes, etc.). RFC-011 OQ-2 asked where the diagrams come from: hand-drawn Inkscape, Figma export, hand-coded SVG in JSON, programmatically generated via D3, or AI-generated. AI-generated was rejected for §principles attribution reasons.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="source-format-rfc-oq-2-—-option-a" tabindex="-1">Source format (RFC OQ-2 — Option A) <a class="header-anchor" href="#source-format-rfc-oq-2-—-option-a" aria-label="Permalink to &quot;Source format (RFC OQ-2 — Option A)&quot;">​</a></h3><p><strong>SVG diagrams live as committed source files</strong> at <code>static/diagrams/science/[section].svg</code>. The canonical authoring tool is open — Inkscape, Figma export, hand-coded SVG markup are all acceptable so long as the resulting <code>.svg</code> file is committed and dark-theme-compatible. The repo source is the authoring source; no separate <code>.fig</code> / <code>.ai</code> / <code>.psd</code> lives outside the tree.</p><p><strong>Rationale</strong>: PRD-008 wants visual style consistency without locking us to one tool. Inkscape is the canonical reference (open source, dark-theme-friendly), but contributors using Figma or hand-coded SVG produce equivalent committed <code>.svg</code> artifacts. Programmatic generation (RFC-011 OQ-2 Option D) is left as a future option for diagrams that need to track data; manual SVG is V1.</p><h3 id="validation-fail-fast-contract" tabindex="-1">Validation (fail-fast contract) <a class="header-anchor" href="#validation-fail-fast-contract" aria-label="Permalink to &quot;Validation (fail-fast contract)&quot;">​</a></h3><p>A new build script <code>scripts/validate-diagrams.ts</code> runs in CI alongside <code>validate-data</code>:</p><ol><li>Loads every section JSON under <code>static/data/science/</code>.</li><li>For each section with a <code>diagram</code> field, asserts <code>static/diagrams/science/[diagram-id].svg</code> exists.</li><li>Fails the build if any reference is missing — same fail-closed model as <code>image-provenance</code> integrity (ADR-046).</li></ol><p>Chained from <code>scripts/validate-data.ts</code> so a single <code>npm run validate-data</code> covers all data integrity.</p><h3 id="visual-style" tabindex="-1">Visual style <a class="header-anchor" href="#visual-style" aria-label="Permalink to &quot;Visual style&quot;">​</a></h3><ul><li>Dark-theme native: transparent background, stroke palette <code>#4ecdc4</code> (teal accent), <code>#4466ff</code> (blue accent), <code>rgba(255,255,255,0.85)</code> (foreground).</li><li>400×300 viewBox standard for desktop; SVG scales responsively at smaller widths.</li><li>No inline <code>&lt;style&gt;</code>; styling via SVG attributes (<code>stroke</code>, <code>fill</code>, <code>stroke-width</code>) so the diagram renders identically in the encyclopedia and in any future export.</li></ul><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><ul><li>Original geometric diagrams: project-owned under MIT (same as the rest of the codebase).</li><li>Photos used in lieu of diagrams: public-domain or CC-BY only, attribution per ADR-046 / ADR-047 image-provenance pipeline.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Cheapest path to V1; consistent visual language; per-section diagram changes are local file edits; CI catches dangling references at build. Future migration to programmatic generation (D3, custom build step) is per-diagram opt-in.</p><p><strong>Negative:</strong> Hand-authored diagrams scale poorly past ~30. If <code>/science</code> doubles in size we&#39;ll revisit programmatic generation. Quality of complex pedagogical illustrations (rocket cutaways, EDL sequences) depends on the contributor; V1 ships schematic-quality SVGs that future contributors can replace with Inkscape passes.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>Diagram directory: <code>static/diagrams/science/</code>.</li><li>Validator: <code>scripts/validate-diagrams.ts</code>, chained into <code>npm run validate-data</code>.</li><li>Quality flag: section JSON&#39;s optional <code>diagram_quality: &quot;schematic&quot; | &quot;polished&quot;</code> field documents which diagrams expect a future polish pass.</li><li>Photos: still allowed (CC-BY / NASA / Wikimedia); section schema accepts either <code>diagram</code> or <code>photo</code>, never both for the primary visual.</li></ul>',21)])])}const h=a(s,[["render",r]]);export{p as __pageData,h as default};
